import { Component, Event, EventEmitter, Host, Prop, State, h } from '@stencil/core';
import type { TaxOption, ServiceCategoryOption } from './ir-city-ledger-transaction-drawer/ir-city-ledger-transaction-form/ir-city-ledger-transaction-form.schema';
import type { FolioFilters, FolioSummary } from './types';
import type { ICurrency } from '@/models/property';

@Component({
  tag: 'ir-city-ledger-folio',
  styleUrl: 'ir-city-ledger-folio.css',
  scoped: true,
})
export class IrCityLedgerFolio {
  @Prop() agentId: number | null = null;
  @Prop() propertyId: number;
  @Prop() taxOptions: TaxOption[] = [];
  @Prop() serviceCategoryOptions: ServiceCategoryOption[] = [];
  @Prop() currencySymbol: string = '$';
  @Prop() currencies: ICurrency[] = [];

  @State() isTransactionOpen: boolean = false;
  @State() filters: FolioFilters = {};

  @Event() folioSummaryUpdate: EventEmitter<FolioSummary>;

  render() {
    return (
      <Host>
        {/* Filters */}
        <ir-city-ledger-folio-filters
          onFiltersChange={e => (this.filters = e.detail)}
          onAddEntry={() => (this.isTransactionOpen = true)}
        ></ir-city-ledger-folio-filters>

        {/* Table */}
        <ir-city-ledger-folio-table
          agentId={this.agentId}
          propertyId={this.propertyId}
          currencySymbol={this.currencySymbol}
          currencies={this.currencies}
          filters={this.filters}
          onFolioSummaryLoaded={e => this.folioSummaryUpdate.emit(e.detail)}
          onGenerateInvoice={e => console.log('Generate invoice for', e.detail)}
        ></ir-city-ledger-folio-table>

        <ir-city-ledger-transaction-drawer
          open={this.isTransactionOpen}
          taxOptions={this.taxOptions}
          serviceCategoryOptions={this.serviceCategoryOptions}
          currencySymbol={this.currencySymbol}
          agentId={this.agentId}
          onTransactionSaved={() => {}}
          onCloseDrawer={() => (this.isTransactionOpen = false)}
        ></ir-city-ledger-transaction-drawer>
      </Host>
    );
  }
}
